private struct UberEatsRestaurantsScreen: View {
    var body: some View {
        ZStack(alignment: .bottom) {
            NavigationStack {
                ScrollView {
                    VStack(alignment: .leading, spacing: 16) {
                        Text("Livraison à Paris 11e").font(.subheadline).foregroundStyle(.secondary).padding(.horizontal)
                        ForEach(UberEatsDemoData.restaurants) { r in UberEatsRestaurantCard(r: r, accent: UberEatsTokens.ueGreen) }
                    }.padding(.vertical)
                }.navigationTitle("Uber Eats")
            }
            UberEatsCartBar(accent: UberEatsTokens.ueGreen)
        }
    }
}

private struct UberEatsRestaurantCard: View {
    let r: UberEatsRestaurant; let accent: Color
    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            RoundedRectangle(cornerRadius: 12).fill(r.color.opacity(0.3)).frame(height: 140)
            HStack {
                VStack(alignment: .leading) {
                    Text(r.name).font(.headline)
                    Text("\(r.cuisine) · \(r.eta) min · \(r.fee)").font(.subheadline).foregroundStyle(.secondary)
                }
                Spacer()
                HStack(spacing: 2) { Image(systemName: "star.fill").foregroundStyle(.orange); Text(r.rating).font(.subheadline.bold()) }
            }.padding(.horizontal)
        }.padding(.bottom, 8)
    }
}

private struct UberEatsCartBar: View {
